def process_tags(tags1, tags2):
    s1, s2 = set(tags1), set(tags2)
    return (s1 & s2, s1 | s2)

hard.solution:
def find_error_nums(nums):
    n = len(nums)
    expected_set = set(range(1, n + 1))
    actual_set = set()
    duplicate = -1
    for x in nums:
        if x in actual_set:
            duplicate = x
        actual_set.add(x)
    missing = list(expected_set - actual_set)[0]
    return (duplicate, missing)
